module top_module(
  input [3:0] a,
  input [3:0] b,
  output reg [3:0] xor_result
);always @* begin
    xor_result[0] = ~(a[0] & b[0]) & (a[0] | b[0]);
    xor_result[1] = ~(a[1] & b[1]) & (a[1] | b[1]);
    xor_result[2] = ~(a[2] & b[2]) & (a[2] | b[2]);
    xor_result[3] = ~(a[3] & b[3]) & (a[3] | b[3]);
  end

endmodule
